<template>  <div class="role-management">    <el-card>      <template #header>        <div class="card-header">          <span>角色管理</span>          <el-button            v-if="authStore.hasPermission('role:create')"            type="primary"            @click="showCreateDialog = true"          >            新增角色          </el-button>        </div>      </template>      <!-- 搜索 -->      <div class="filter-section">        <el-input          v-model="searchKeyword"          placeholder="搜索角色名称或描述"          style="width: 300px;"          clearable          @input="handleSearch"        />      </div>      <!-- 角色列表 -->      <el-table        :data="filteredRoles"        style="width: 100%"        v-loading="loading"      >        <el-table-column prop="id" label="ID" width="80" />        <el-table-column prop="name" label="角色名称" width="150" />        <el-table-column prop="description" label="描述" />        <el-table-column prop="createdAt" label="创建时间" width="180">          <template #default="scope">            {{ formatDate(scope.row.createdAt) }}          </template>        </el-table-column>        <el-table-column label="权限数量" width="100">          <template #default="scope">            <el-tag type="info">{{ scope.row.permissions?.length || 0 }}</el-tag>          </template>        </el-table-column>        <el-table-column label="权限列表" min-width="200">          <template #default="scope">            <el-tag              v-for="permission in scope.row.permissions"              :key="permission.id"              size="small"              style="margin: 2px;"            >              {{ permission.name }}            </el-tag>          </template>        </el-table-column>        <el-table-column label="操作" width="250" fixed="right">          <template #default="scope">            <el-button              v-if="authStore.hasPermission('role:update')"              type="primary"              size="small"              @click="editRole(scope.row)"            >              编辑            </el-button>            <el-button              v-if="authStore.hasPermission('role:update')"              type="warning"              size="small"              @click="managePermissions(scope.row)"              style="margin-left: 5px;"            >              权限管理            </el-button>            <el-button              v-if="authStore.hasPermission('role:delete')"              type="danger"              size="small"              @click="deleteRole(scope.row)"              style="margin-left: 5px;"            >              删除            </el-button>          </template>        </el-table-column>      </el-table>      <!-- 分页 -->      <div class="pagination">        <el-pagination          v-model:current-page="currentPage"          v-model:page-size="pageSize"          :page-sizes="[10, 20, 50, 100]"          :total="totalRoles"          layout="total, sizes, prev, pager, next, jumper"          @size-change="handleSizeChange"          @current-change="handleCurrentChange"        />      </div>    </el-card>    <!-- 新增/编辑角色对话框 -->    <el-dialog      v-model="showCreateDialog"      :title="isEditing ? '编辑角色' : '新增角色'"      width="500px"    >      <el-form        ref="roleFormRef"        :model="roleForm"        :rules="roleRules"        label-width="80px"      >        <el-form-item label="角色名称" prop="name">          <el-input            v-model="roleForm.name"            :disabled="isEditing"            placeholder="请输入角色名称"          />        </el-form-item>        <el-form-item label="描述" prop="description">          <el-input            v-model="roleForm.description"            type="textarea"            placeholder="请输入角色描述"          />        </el-form-item>        <el-form-item label="权限" prop="permissionIds">          <el-select            v-model="roleForm.permissionIds"            multiple            placeholder="选择权限"            style="width: 100%"            filterable          >            <el-option              v-for="permission in allPermissions"              :key="permission.id"              :label="`${permission.name} - ${permission.description}`"              :value="permission.id"            />          </el-select>        </el-form-item>      </el-form>      <template #footer>        <span class="dialog-footer">          <el-button @click="showCreateDialog = false">取消</el-button>          <el-button            type="primary"            :loading="submitLoading"            @click="handleSubmit"          >            {{ isEditing ? '更新' : '创建' }}          </el-button>        </span>      </template>    </el-dialog>    <!-- 权限管理对话框 -->    <el-dialog      v-model="showPermissionDialog"      title="权限管理"      width="600px"    >      <div class="permission-management">        <div class="current-permissions">          <h4>当前权限：</h4>          <el-tag            v-for="permission in currentRolePermissions"            :key="permission.id"            size="small"            closable            @close="removePermission(permission.id)"            style="margin: 5px;"          >            {{ permission.name }}          </el-tag>        </div>        <el-divider />        <div class="add-permissions">          <h4>添加权限：</h4>          <el-select            v-model="selectedPermissionId"            placeholder="选择要添加的权限"            style="width: 100%; margin-bottom: 10px;"            filterable          >            <el-option              v-for="permission in availablePermissions"              :key="permission.id"              :label="`${permission.name} - ${permission.description}`"              :value="permission.id"            />          </el-select>          <el-button            type="primary"            size="small"            @click="addPermission"            :disabled="!selectedPermissionId"          >            添加权限          </el-button>        </div>      </div>    </el-dialog>  </div></template><script>import { ref, reactive, onMounted, computed } from 'vue'import { useAuthStore } from '../stores/auth'import axios from 'axios'import { ElMessage, ElMessageBox } from 'element-plus'export default {  name: 'RoleManagementView',  setup() {    const authStore = useAuthStore()    const roles = ref([])    const allPermissions = ref([])    const loading = ref(false)    const submitLoading = ref(false)    const showCreateDialog = ref(false)    const showPermissionDialog = ref(false)    const isEditing = ref(false)    const searchKeyword = ref('')    const currentPage = ref(1)    const pageSize = ref(10)    const totalRoles = ref(0)    const selectedPermissionId = ref(null)    const currentRole = ref(null)    const currentRolePermissions = ref([])    const roleFormRef = ref()    const roleForm = reactive({      id: null,      name: '',      description: '',      permissionIds: []    })    const roleRules = {      name: [        { required: true, message: '请输入角色名称', trigger: 'blur' },        { min: 2, max: 50, message: '角色名称长度在 2 到 50 个字符', trigger: 'blur' }      ],      description: [        { max: 200, message: '描述不能超过 200 个字符', trigger: 'blur' }      ]    }    // 计算过滤后的角色列表    const filteredRoles = computed(() => {      let filtered = roles.value      // 搜索关键词      if (searchKeyword.value) {        filtered = filtered.filter(role =>          role.name.toLowerCase().includes(searchKeyword.value.toLowerCase()) ||          (role.description && role.description.toLowerCase().includes(searchKeyword.value.toLowerCase()))        )      }      // 分页      const start = (currentPage.value - 1) * pageSize.value      const end = start + pageSize.value      // totalRoles.value = filtered.length      return filtered.slice(start, end)    })    // 计算可用的权限（当前角色没有的权限）    const availablePermissions = computed(() => {      if (!currentRolePermissions.value.length) return allPermissions.value      const currentPermissionIds = currentRolePermissions.value.map(p => p.id)      return allPermissions.value.filter(p => !currentPermissionIds.includes(p.id))    })    const fetchRoles = async () => {      if (!authStore.hasPermission('role:list')) return      loading.value = true      try {        const response = await axios.get('http://localhost:3000/api/roles', {          headers: { Authorization: `Bearer ${authStore.accessToken}` }        })        if (response.data.success) {          roles.value = response.data.data        }      } catch (error) {        console.error('Fetch roles error:', error)        ElMessage.error('获取角色列表失败')      } finally {        loading.value = false      }    }    const fetchPermissions = async () => {      try {        const response = await axios.get('http://localhost:3000/api/roles/permissions', {          headers: { Authorization: `Bearer ${authStore.accessToken}` }        })        if (response.data.success) {          allPermissions.value = response.data.data        }      } catch (error) {        console.error('Fetch permissions error:', error)      }    }    const handleSearch = () => {      currentPage.value = 1    }    const handleSizeChange = (val) => {      pageSize.value = val      currentPage.value = 1    }    const handleCurrentChange = (val) => {      currentPage.value = val    }    const resetForm = () => {      roleForm.id = null      roleForm.name = ''      roleForm.description = ''      roleForm.permissionIds = []    }    const editRole = (role) => {      isEditing.value = true      roleForm.id = role.id      roleForm.name = role.name      roleForm.description = role.description || ''      roleForm.permissionIds = role.permissions ? role.permissions.map(p => p.id) : []      showCreateDialog.value = true    }    const managePermissions = (role) => {      currentRole.value = role      currentRolePermissions.value = [...(role.permissions || [])]      showPermissionDialog.value = true    }    const deleteRole = async (role) => {      try {        await ElMessageBox.confirm(          `确定要删除角色 "${role.name}" 吗？此操作不可恢复。`,          '确认删除',          {            confirmButtonText: '确定',            cancelButtonText: '取消',            type: 'warning',          }        )        const response = await axios.delete(`http://localhost:3000/api/roles/${role.id}`, {          headers: { Authorization: `Bearer ${authStore.accessToken}` }        })        if (response.data.success) {          ElMessage.success('删除成功')          fetchRoles()        }      } catch (error) {        if (error !== 'cancel') {          console.error('Delete role error:', error)          ElMessage.error('删除失败')        }      }    }    const handleSubmit = async () => {      try {        await roleFormRef.value.validate()        submitLoading.value = true        const formData = {          name: roleForm.name,          description: roleForm.description || undefined,          permissions: roleForm.permissionIds        }        let response        if (isEditing.value) {          if (!authStore.hasPermission('role:update')) {            ElMessage.error('没有编辑权限')            return          }          response = await axios.put(`http://localhost:3000/api/roles/${roleForm.id}`, formData, {            headers: { Authorization: `Bearer ${authStore.accessToken}` }          })        } else {          if (!authStore.hasPermission('role:create')) {            ElMessage.error('没有创建权限')            return          }          response = await axios.post('http://localhost:3000/api/roles', formData, {            headers: { Authorization: `Bearer ${authStore.accessToken}` }          })        }        if (response.data.success) {          ElMessage.success(isEditing.value ? '更新成功' : '创建成功')          showCreateDialog.value = false          resetForm()          fetchRoles()        }      } catch (error) {        console.error('Submit role error:', error)        ElMessage.error(error.response?.data?.message || '操作失败')      } finally {        submitLoading.value = false      }    }    const addPermission = async () => {      if (!selectedPermissionId.value || !currentRole.value) return      try {        const response = await axios.post(`http://localhost:3000/api/roles/${currentRole.value.id}/permissions`, {          permissionId: selectedPermissionId.value        }, {          headers: { Authorization: `Bearer ${authStore.accessToken}` }        })        if (response.data.success) {          ElMessage.success('权限添加成功')          selectedPermissionId.value = null          // 重新获取角色详情          const roleResponse = await axios.get(`http://localhost:3000/api/roles/${currentRole.value.id}`, {            headers: { Authorization: `Bearer ${authStore.accessToken}` }          })          if (roleResponse.data.success) {            currentRolePermissions.value = roleResponse.data.data.permissions || []          }          fetchRoles() // 刷新列表        }      } catch (error) {        console.error('Add permission error:', error)        ElMessage.error('添加权限失败')      }    }    const removePermission = async (permissionId) => {      if (!currentRole.value) return      try {        const response = await axios.delete(`http://localhost:3000/api/roles/${currentRole.value.id}/permissions`, {          data: { permissionId },          headers: { Authorization: `Bearer ${authStore.accessToken}` }        })        if (response.data.success) {          ElMessage.success('权限移除成功')          // 更新本地状态          currentRolePermissions.value = currentRolePermissions.value.filter(p => p.id !== permissionId)          fetchRoles() // 刷新列表        }      } catch (error) {        console.error('Remove permission error:', error)        ElMessage.error('移除权限失败')      }    }    const formatDate = (dateString) => {      return new Date(dateString).toLocaleString('zh-CN')    }    onMounted(() => {      fetchRoles()      fetchPermissions()    })    return {      authStore,      roles,      allPermissions,      loading,      submitLoading,      showCreateDialog,      showPermissionDialog,      isEditing,      searchKeyword,      currentPage,      pageSize,      totalRoles,      filteredRoles,      selectedPermissionId,      currentRolePermissions,      availablePermissions,      roleFormRef,      roleForm,      roleRules,      handleSearch,      handleSizeChange,      handleCurrentChange,      editRole,      managePermissions,      deleteRole,      handleSubmit,      addPermission,      removePermission,      formatDate    }  }}</script><style scoped>.role-management {  padding: 20px;}.card-header {  display: flex;  justify-content: space-between;  align-items: center;}.filter-section {  margin-bottom: 20px;}.pagination {  margin-top: 20px;  text-align: right;}.dialog-footer {  text-align: right;}.permission-management {  max-height: 400px;  overflow-y: auto;}.current-permissions h4,.add-permissions h4 {  margin: 0 0 10px 0;  color: #409eff;}.current-permissions {  margin-bottom: 20px;}</style>